export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言繞過最後一排器材箱的時候，鞋底在積水上打了一下滑。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有停。膝蓋撐住，手掌在箱角上一撐，把自己甩進了通道。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了許星棠。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她蹲在直播控制台旁邊，相機包打開著，一條備份線從相機接口伸出來，另一端捏在她手裡。她的手指在控制台的備份口上摸索——插不進去。接口旁邊的螢幕亮著一行字：密碼未解。線路未通。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.XuXingtang_Urgent },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的嘴唇壓成一條線。手指在備份口的邊緣摸索，像在找一個不存在的入口。密碼。還是密碼。那個加密檔——GZ_給小言_最後備份——從第六輪到現在，她一次都沒有打開過。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑雨衣的人影離她只有兩步。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）來不及了。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他已經到了。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言衝過去。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是繞。不是迂迴。是直線。五步。四步。三步——", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔動了。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是轉身。不是面對顧言。是側步。很小。像早就知道顧言會從這個角度衝過來一樣——他只是把重心往左移了半步，在顧言衝到最近的瞬間，用肩膀接住了顧言的衝勢，然後順著那股衝力，把顧言引向旁邊的設備箱。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最少動作。最精準角度。不是打架。是控制。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的腰撞上設備箱的金屬邊緣。痛感從腰側炸開，沿著肋骨往上竄。他的膝蓋一軟，半跪在地上。耳朵裡嗡了一聲。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他——", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他知道我會衝過來。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是因為循環。是因為他了解我。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他知道我一旦確認真相——", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）一定會衝過來。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔沒有看顧言。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的注意力在許星棠身上。在相機上。他的手伸向相機包——動作和第五章在玻璃反光裡看見的一樣：很快，很準，沒有猶豫。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.XuXingtang_Afraid },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠抬起頭。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見了邵叔的臉。帽沿壓得低，但她認得出那張臉。她的身體縮了一下——和第五章一模一樣的反應。不是困惑。不是「你是誰」。是恐懼。是那種早就知道對方會來、只是不確定什麼時候來的恐懼。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把相機包往懷裡收。指節發白。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從地上撲起來。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是站起來。是撲。膝蓋還在痛，腰還在痛，但他不管了。他整個人撲向邵叔的手——抓住了雨衣的袖子。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "——不要碰她。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔低頭看了他一眼。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "帽沿下面，那雙眼睛沒有溫度。不是憤怒。不是慌張。是一種很平的、像在評估一件東西還能用多久的眼神。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他開口了。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很低。低到只有顧言聽得見。低到被暴雨、掌聲、倒數聲一起蓋住，不會有第三個人聽到。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "你爸當年也是這樣，非要把事情弄到所有人面前。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.ShaoQiming_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一句話。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是解釋。不是自白。不是反派在死前交代動機。是一根刺。很短。很準。扎進顧言腦子裡十年前那個他一直拼不完整的畫面裡。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我爸。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說我爸。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說「當年」。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說「也是這樣」。", background: Background.Chapter_7_Ch7_Act18_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的手鬆了。不是放棄。是那根刺扎進去的瞬間，他的身體像被抽走了一秒的力氣。就一秒。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔把他的手從袖子上撥開。動作很小。像撥開一根樹枝。", background: Background.Chapter_7_Ch7_Act18_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔轉向許星棠。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠還在摸索備份口。密碼未解。線路未通。她的手指在發抖，但她沒有放開相機。她用整個身體擋在控制台和邵叔之間——背對著他，肩膀縮起來，像在用自己擋住一顆子彈。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她擋的不是子彈。是一台相機。一張記憶卡。一段十年前的真相。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——十——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）站起來。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯站起來。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言撐著設備箱站起來。腰還在痛。膝蓋還在抖。但他站起來了。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——九——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的手抓住了相機包的背帶。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "——不要。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.XuXingtang_Afraid },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的聲音很小。不是喊。是那種被壓到最低的、像從牙縫裡擠出來的拒絕。她的手指扣在拉鏈上，扣得指節發白。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——八——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔拉。許星棠不鬆。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個人在相機包的背帶上僵持了兩秒。邵叔沒有用全力——他不想弄出太大的動靜，後台外面就是走廊，走廊外面就是禮堂。他需要的是快、安靜、不留痕跡。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但許星棠不鬆手。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——七——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言再次撲上去。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次他沒有喊。他撲向邵叔的手臂，想把他從許星棠身上拉開——但邵叔的肩膀一沉，用肘部把顧言頂開。力道不大，但角度精準，正好頂在顧言胸口的軟肋上。顧言退了兩步，背撞上牆壁。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他沒有用力。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在控制力度。不想讓我倒下。不想讓我出聲。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他還在演。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）就算現在，他還在演「沒有發生過任何事」。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——六——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——五——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔放棄了拉扯相機包。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他換了策略。他的手從背帶上鬆開，轉而按住許星棠的肩膀——把她從控制台前推開。推力不大，但方向是朝設備箱的邊緣。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的腳在積水上滑了。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的後背撞上設備箱的金屬邊角。不是很重。但在那個角度、那個位置——她的後腦撞上了箱體的邊緣。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那聲悶響很小。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在暴雨、掌聲、倒數裡，幾乎聽不見。但顧言聽見了。因為他一直在聽。因為他每一輪都在聽這個聲音。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——四——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的身體軟了。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是倒下。是鬆開。像一根繃了很久的弦突然斷了。她的手指從相機包的拉鏈上鬆開。膝蓋先跪下去，然後整個人往側邊倒。肩膀著地。然後頭。她的眼睛還睜著，但瞳孔已經不在焦點上了。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "相機包從她懷裡滑出來。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "落在地上。悶的一聲。金屬扣件在水泥地上彈了一下，發出一聲很細的叮。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——三——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不不不不不——", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言爬過去。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的膝蓋在積水上跪著，手撐在地上，爬到許星棠身邊。他把手伸到她的脖子旁邊——找脈搏。手指在發抖。他找不準。他不知道自己摸到的是她脖子上的筋還是動脈。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的嘴唇動了一下。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕。幾乎看不出來。像在壓住一個字。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後不動了。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的眼睛還睜著。但裡面的光沒了。那種深水一樣的、安靜的亮——沒了。變成了一個平面的、不再反射任何東西的表面。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她——", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她沒有——", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——二——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔站在三步之外。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有看許星棠。他在看顧言。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手從雨衣袖子裡伸出來。不是伸向相機。是伸向顧言。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他開始走向顧言。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他過來了。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他走過來了。", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他——", background: Background.Chapter_7_Ch7_Act18_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Mc, character: "主持人", dialogue: "——一——", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "23:00。", background: Background.Chapter_7_Ch7_Act18_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "倒數聲斷了。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是喊完的。是在「一」之後，突然沒有了。像有人把音量旋鈕一把轉到底。掌聲沒了。雨聲沒了。主持人的聲音沒了。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言低頭。手機螢幕亮著。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "上面的數字停在 23:00。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有跳到 23:01。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "永遠不會跳了。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）又來了。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "世界開始從邊緣褪色。設備箱的輪廓變白。地上的相機包變白。許星棠倒下的影子變白。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔伸向他的那隻手，也變白了。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他正要——", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他正要走過來。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是放過我。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他是——", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯她先走了。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她先死了。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）世界就回來了。", background: Background.Chapter_7_Ch7_Act18_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白色填滿了一切。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最後一個消失的聲音，是那聲相機落地的悶響。它在白色的空無裡迴盪了一下。", background: Background.Chapter_7_Ch7_Act18_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後什麼都沒有了。", background: Background.Chapter_7_Ch7_Act18_S2 },
];
